INSERT INTO `custom_services` VALUES (1,'website','تطوير مواقع الويب','Website Development','مواقع احترافية تعكس هويتك وتجذب عملاءك','Professional websites that reflect your brand and attract clients','نبني مواقع ويب عصرية وسريعة ومتوافقة مع جميع الأجهزة. من المواقع التعريفية إلى المتاجر الإلكترونية والمنصات الضخمة — نصمم ونطور حسب احتياجاتك.','We build modern, fast, fully responsive websites. From landing pages to e-commerce platforms and enterprise portals — designed and developed to your exact needs.','ابتداءً من ٥٠٠ $','Starting from $500','[\"تصميم UI/UX احترافي\", \"متوافق مع جميع الأجهزة\", \"سرعة تحميل فائقة\", \"لوحة تحكم سهلة\", \"تحسين محركات البحث SEO\", \"شهادة SSL مجانية\"]','[\"Professional UI/UX Design\", \"Fully Responsive\", \"Lightning Fast Loading\", \"Easy Admin Panel\", \"SEO Optimization\", \"Free SSL Certificate\"]','[\"React.js\", \"Next.js\", \"Node.js\", \"MySQL\", \"TailwindCSS\"]','[\"React.js\", \"Next.js\", \"Node.js\", \"MySQL\", \"TailwindCSS\"]','https://images.unsplash.com/photo-1467232004584-a241de8bcf5d?q=80&w=800',1,1,'2026-03-28 18:20:45'),(2,'desktop','تطوير تطبيقات سطح المكتب','Desktop App Development','برامج قوية تعمل على Windows وmacOS وLinux','Powerful apps running on Windows, macOS and Linux','نطور تطبيقات سطح المكتب بأداء عالٍ وواجهات مستخدم سلسة. من أنظمة إدارة الأعمال إلى الأدوات التقنية المتخصصة، نبني ما تحتاجه بأحدث التقنيات.','We develop high-performance desktop applications with smooth UIs. From business management systems to specialized tools — we build what you need with modern technology.','ابتداءً من ٢٠٠٠ $','Starting from $2,000','[\"أداء عالٍ وسرعة فائقة\", \"يعمل بدون إنترنت\", \"تكامل مع قواعد البيانات\", \"واجهة مستخدم احترافية\", \"تحديثات تلقائية\", \"دعم فني مستمر\"]','[\"High Performance\", \"Works Offline\", \"Database Integration\", \"Professional UI\", \"Auto Updates\", \"Ongoing Support\"]','[\"Electron.js\", \"C# / .NET\", \"WPF\", \"SQLite\", \"Tauri\"]','[\"Electron.js\", \"C# / .NET\", \"WPF\", \"SQLite\", \"Tauri\"]','https://images.unsplash.com/photo-1593642632559-0c6d3fc62b89?q=80&w=800',2,1,'2026-03-28 18:20:45'),(3,'mobile','تطوير تطبيقات الجوال','Mobile App Development','تطبيقات iOS وAndroid تصل لعملائك في أي مكان','iOS & Android apps that reach your customers anywhere','نصنع تطبيقات موبايل ذكية وجميلة لنظامي iOS وAndroid. من فكرتك الأولى حتى النشر على المتاجر — فريقنا يرافقك في كل خطوة.','We craft smart, beautiful mobile apps for iOS and Android. From your first idea to App Store launch — our team is with you every step of the way.','ابتداءً من ٣٠٠٠ $','Starting from $3,000','[\"تصميم UI/UX مخصص\", \"يعمل على iOS وAndroid\", \"إشعارات فورية\", \"تكامل مع APIs\", \"نشر على المتاجر\", \"تحليلات وتقارير\"]','[\"Custom UI/UX Design\", \"iOS & Android\", \"Push Notifications\", \"API Integration\", \"Store Deployment\", \"Analytics & Reports\"]','[\"React Native\", \"Flutter\", \"Swift\", \"Kotlin\", \"Firebase\"]','[\"React Native\", \"Flutter\", \"Swift\", \"Kotlin\", \"Firebase\"]','https://images.unsplash.com/photo-1512941937669-90a1b58e7e9c?q=80&w=800',3,1,'2026-03-28 18:20:45');
