INSERT INTO `product_faqs` VALUES (91,4,'هل يدعم تذكير المواعيد؟','Does it support appointment reminders?','نعم، يمكن تفعيل تذكيرات تساعد على تقليل الغياب.','Yes. Reminders can be enabled to reduce no-shows.'),(92,4,'هل يوجد ملف مريض وسجل زيارات؟','Do you have a patient profile and visit history?','نعم، ملف المريض يجمع البيانات والتشخيصات والوصفات وتاريخ الزيارات.','Yes. Patient profiles include data, diagnoses, prescriptions, and visit history.'),(93,4,'هل يوجد صلاحيات للطاقم؟','Are staff permissions supported?','نعم، صلاحيات حسب الدور للطبيب والاستقبال والمحاسبة.','Yes. Role-based permissions for doctors, reception, and billing staff.'),(94,4,'هل يدعم أكثر من عيادة/طبيب؟','Does it support multiple doctors/clinics?','نعم، مناسب للعيادة الواحدة أو عدة عيادات وأطباء.','Yes. Works for single clinics or multi-doctor setups.'),(95,4,'هل يوجد تقارير؟','Are there reports?','نعم، تقارير للمواعيد والإيرادات وأداء العيادة حسب المتاح.','Yes. Reports for appointments, revenue, and clinic performance (depending on plan).'),(96,3,'هل مناسب للمستشفيات الكبيرة؟','Is it suitable for large hospitals?','نعم، مصمم ليكون قابل للتوسع حسب عدد الأقسام والمستخدمين.','Yes. Designed to scale based on departments and user count.'),(97,3,'هل يوجد صلاحيات وتدقيق؟','Does it have permissions and auditing?','نعم، صلاحيات حسب الدور ويمكن إضافة سجلات تدقيق حسب الحاجة.','Yes. Role-based access and auditing can be enabled as needed.'),(98,3,'هل يوفر لوحات متابعة للإدارة؟','Does it provide management dashboards?','نعم، لوحات مؤشرات وتقارير لمتابعة الأداء.','Yes. KPI dashboards and analytics reports are included.'),(99,3,'هل يمكن تخصيص سير العمل؟','Can workflows be customized?','نعم، يمكن تهيئة الأقسام والعمليات وفق طبيعة المستشفى.','Yes. Departments and processes can be configured to match your operations.'),(100,3,'هل يوجد تدريب وتشغيل؟','Do you provide onboarding?','نوفر تدريب وتشغيل مبدئي ودعم مستمر حسب الاتفاق.','We provide onboarding and ongoing support based on the agreement.'),(101,5,'هل يدعم الباركود وتتبع العينات؟','Does it support barcodes and sample tracking?','نعم، يدعم تسجيل العينات مع باركود وتتبع مراحلها حتى إصدار التقرير.','Yes. You can register samples with barcodes and track them through all stages until reporting.'),(102,5,'هل يمكن تخصيص التقارير؟','Can reports be customized?','نعم، يمكن تخصيص شكل التقرير والحقول وفق احتياجات المعمل.','Yes. Report templates and fields can be customized to your lab’s needs.'),(103,5,'هل يوجد صلاحيات للمستخدمين؟','Is there role-based access control?','نعم، صلاحيات متعددة حسب الدور (استقبال/فني/مشرف/مدير).','Yes. Multiple roles and permissions (reception/technician/supervisor/admin).'),(104,5,'هل يدعم تعدد الفروع؟','Does it support multiple branches?','نعم، يمكن تشغيله لعدة فروع مع تقارير موحدة أو لكل فرع.','Yes. Multi-branch setup with unified reporting or branch-level reporting.'),(105,5,'هل يوجد دعم فني وتدريب؟','Do you provide support and training?','نوفر تدريب عند التشغيل ودعم فني حسب الباقة.','We provide onboarding training and support depending on your plan.');
/*!40000 ALTER TABLE `product_faqs` ENABLE KEYS */;
UNLOCK TABLES;

