INSERT INTO `product_how_it_works` VALUES (55,4,'حجز وإدارة المواعيد','Schedule appointments','تقويم مرن للمواعيد مع تذكيرات وتقليل الغياب.','Flexible scheduling with reminders to reduce no-shows.'),(56,4,'ملف المريض والسجل الطبي','Patient profile & EMR','كل بيانات المريض في مكان واحد مع تاريخ الزيارات.','Keep patient data in one place with visit history.'),(57,4,'فواتير وتقارير','Billing & reports','فواتير منظمة وتقارير أداء تساعدك على المتابعة.','Structured billing and performance reports for better tracking.'),(58,3,'إدخال ومتابعة الحالة','Admission & case tracking','إجراءات إدخال منظمة مع متابعة الحالة ومراحل الخدمة.','Structured admission process with case tracking across services.'),(59,3,'إدارة الأقسام','Department operations','تنسيق بين الأقسام مع صلاحيات وسير عمل واضح.','Coordinate departments with clear workflows and permissions.'),(60,3,'لوحات وتقارير للإدارة','Dashboards & analytics','لوحات متابعة وتقارير تساعد الإدارة على اتخاذ قرارات أسرع.','Dashboards and analytics to help management make faster decisions.'),(61,5,'استقبال وتسجيل العينة','Receive & register samples','سجّل بيانات المريض والعينة بسرعة، واطبع باركود للتتبع.','Register patient & sample data fast and print barcodes for tracking.'),(62,5,'تتبّع سير العمل','Track workflow','تابع مراحل التحليل والحالة لحظة بلحظة مع تنبيهات تلقائية.','Monitor processing stages in real time with automated alerts.'),(63,5,'نتائج وتقارير','Results & reporting','اعتمد النتائج واصدر تقارير احترافية قابلة للتخصيص.','Approve results and generate professional, customizable reports.');
