INSERT INTO `product_images` VALUES (73,4,'/placeholder.svg','لوحة العيادة','Clinic dashboard','متابعة سريعة للمواعيد والزيارات.','Quick view of appointments and visits.'),(74,4,'/placeholder.svg','المواعيد','Appointments','تقويم واضح وإدارة سهلة.','Clear calendar and easy management.'),(75,4,'/placeholder.svg','ملف المريض','Patient profile','سجل طبي إلكتروني منظم.','Organized electronic medical record.'),(76,4,'/placeholder.svg','الفواتير','Billing','فواتير وتقارير مالية.','Invoices and financial reports.'),(77,3,'/placeholder.svg','لوحة المستشفى','Hospital dashboard','مؤشرات أساسية في مكان واحد.','Key KPIs in one place.'),(78,3,'/placeholder.svg','لوحات الإدارة','Admin dashboards','متابعة الأقسام والضغط التشغيلي.','Monitor departments and workload.'),(79,3,'/placeholder.svg','الأقسام والخدمات','Departments & services','تنظيم العمليات بين الأقسام.','Organize cross-department operations.'),(80,3,'/placeholder.svg','التقارير','Reports','تقارير تشغيلية وإدارية.','Operational and management reports.'),(81,5,'data:image/webp;base64,','لوحة التحكم','Dashboard','نظرة عامة على الحالات والمهام.','A quick overview of cases and tasks.'),(82,5,'data:image/webp;base64,','النتائج','Results','اعتماد النتائج ومراجعتها بسهولة.','Review and approve results easily.'),(83,5,'data:image/webp;base64,','التقارير','Reports','قوالب تقارير قابلة للتخصيص.','Customizable report templates.'),(84,5,'data:image/webp;base64,','تتبّع العينة','Sample tracking','تتبّع كامل بالباركود.','End-to-end tracking with barcodes.');
