INSERT INTO `product_success` VALUES (37,4,'د. محمد','Dr. Mohamed','طبيب','Physician','المواعيد والسجل الطبي الإلكتروني بقوا أسرع وواضحين للطاقم كله.','Appointments and EMR became faster and clearer for the whole staff.'),(38,4,'إدارة العيادة','Clinic Management','','','التقارير والفواتير ساعدتنا في متابعة الأداء وزيادة الالتزام.','Reports and billing helped us monitor performance and improve compliance.'),(39,3,'إدارة المستشفى','Hospital Administration','','','لوحات المتابعة والتقارير خلت القرارات أسرع وإدارة الأقسام أكثر كفاءة.','Dashboards and reports made decisions faster and department management more efficient.'),(40,3,'قسم الاستقبال','Reception Team','','','تنظيم الإدخال والمتابعة قلل الأخطاء وسرّع الخدمة.','Admission and follow-up organization reduced errors and sped up service.'),(41,5,'د. أحمد','Dr. Ahmed','مدير معمل','Lab Director','GoLab ساعدنا نقلل زمن إصدار النتائج ونحسن دقة التقارير بشكل ملحوظ.','GoLab helped us reduce turnaround time and significantly improve reporting accuracy.'),(42,5,'أ. سارة','Sara','مسؤول تشغيل','Operations','تتبع العينات والتنبيهات خلّى الشغل منظم وسهل على الفريق.','Sample tracking and alerts made the workflow organized and easy for the team.');
