INSERT INTO `products` VALUES (3,'gohospital','hospital','bg-accent text-accent-foreground','GoHospital','GoHospital','نظام متكامل لإدارة عمليات المستشفى','A comprehensive hospital operations system','من الاستقبال وحتى الخروج: إدارة الأقسام، المرضى، الخدمات، التقارير، ولوحات متابعة للإدارة.','From admission to discharge: manage departments, patients, services, reporting, and management dashboards.','ابتداءً من ٥٠٠٠ $/سنوياً','Starting from $5,000/year',NULL,NULL,'#','201111536173','مرحباً، أريد معرفة تفاصيل GoHospital وطلب تجربة.','Hi, I’d like details about GoHospital and request a trial.','https://www.facebook.com/golabsys','https://images.unsplash.com/photo-1519494026892-80bbd2d6fd0d?q=80&w=800','/placeholder.svg','قائمة أسعار GoHospital','GoHospital pricing list','2026-03-26 15:08:11',3),(4,'goclinic','clinic','bg-secondary/10 text-secondary','GoClinic','GoClinic','حل رقمي متطور لإدارة العيادات','An advanced digital clinic solution','إدارة المواعيد والمرضى والسجل الطبي الإلكتروني، مع تجربة استخدام بسيطة للطبيب والاستقبال.','Manage appointments, patients, and EMR with an easy experience for doctors and reception staff.','ابتداءً من ٢٠٠٠ $/سنوياً','Starting from $2,000/year',NULL,NULL,'data:application/pdf;base64,','201111536173','مرحباً، أريد معرفة تفاصيل GoClinic وطلب تجربة.','Hi, I’d like details about GoClinic and request a trial.','https://www.facebook.com/golabsys','data:image/webp;base64,','/placeholder.svg','قائمة أسعار GoClinic','GoClinic pricing list','2026-03-26 16:00:46',2),(5,'golab','lab','bg-primary/10 text-primary','GoLab','GoLab','نظام إدارة شامل للمختبرات الطبية','A comprehensive lab management system','حل متكامل لإدارة سير العمل داخل المعمل: تسجيل العينات، تتبعها، إصدار النتائج والتقارير، والتكامل مع الأجهزة.','An end-to-end lab workflow solution: sample registration, tracking, results & reporting, with device integration support.','ابتداءً من 1٠٠٠ ','Starting from 1000','jwutkCPspgw','https://www.youtube.com/watch?v=SqcY0GlETPk','data:application/pdf;base64,','201111536173','مرحباً، أريد معرفة تفاصيل GoLab وطلب تجربة.','Hi, I’d like details about GoLab and request a trial.','https://www.facebook.com/golabsys','data:image/webp;base64,','data:image/webp;base64,','Pricing','Pricing','2026-03-28 17:35:03',1);
